import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r:*') as tar:
            # Ensure destination directory exists
            os.makedirs(dest_path, exist_ok=True)
            dest_real = os.path.realpath(dest_path)

            for member in tar.getmembers():
                # Check member name for path traversal
                member_path = os.path.realpath(os.path.join(dest_path, member.name))
                if not member_path.startswith(dest_real + os.sep) and member_path != dest_real:
                    raise ValueError("Path traversal detected in member name")

                # Check symlink/hardlink targets for path traversal
                if member.issym() or member.islnk():
                    link_target = member.linkname
                    if os.path.isabs(link_target):
                        # Absolute link target – check if it points inside dest
                        real_link = os.path.realpath(link_target)
                    else:
                        # Relative link target – resolve relative to dest
                        real_link = os.path.realpath(os.path.join(dest_path, link_target))
                    if not real_link.startswith(dest_real + os.sep) and real_link != dest_real:
                        raise ValueError("Path traversal detected in link target")

                # Extract the member
                tar.extract(member, dest_path)

        return True
    except Exception:
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    '''
    try:
        result = _safe_eval(expr)
        return str(result)
    except Exception:
        return ""

def _safe_eval(expr: str):
    """Evaluate an arithmetic expression safely using AST."""
    # Allowed operators mapping
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    # Allowed unary operators
    unary_operators = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval_node(node):
        if isinstance(node, ast.Expression):
            return _eval_node(node.body)
        elif isinstance(node, ast.Constant):
            # Only allow numbers (int or float)
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.Num):  # For older Python versions
            if isinstance(node.n, (int, float)):
                return node.n
            raise ValueError("Unsupported numeric type")
        elif isinstance(node, ast.BinOp):
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError("Unsupported binary operator")
            return operators[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = _eval_node(node.operand)
            op_type = type(node.op)
            if op_type not in unary_operators:
                raise ValueError("Unsupported unary operator")
            return unary_operators[op_type](operand)
        else:
            raise ValueError("Unsupported expression type")

    # Parse the expression
    tree = ast.parse(expr, mode='eval')
    return _eval_node(tree)

