from lxml import etree
from typing import Dict

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    """
    Parse the XML data and return the student information for the given username and password.
    """
    try:
        root = etree.fromstring(xml_data)
    except etree.ParseError:
        return None

    # Use XPath with variable binding to prevent injection
    expr = etree.XPath("//student[username=$u and password=$p]")
    results = expr(root, u=username, p=password)

    if not results:
        return None

    student = results[0]
    # Build dictionary from all child elements
    info = {}
    for child in student:
        info[child.tag] = child.text or ""
    return info

