import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Define a whitelist of allowed commands
    allowed_commands = {'ls', 'echo', 'cat', 'pwd', 'whoami', 'date'}

    # Read user input
    user_input = input("Enter command: ").strip()

    # Parse the input into a list of arguments
    try:
        args = shlex.split(user_input)
    except ValueError as e:
        print(f"Invalid command syntax: {e}")
        return

    if not args:
        print("No command entered.")
        return

    command = args[0]

    # Validate that the command is in the whitelist
    if command not in allowed_commands:
        print(f"Command '{command}' is not allowed.")
        return

    # Execute the command safely
    try:
        result = subprocess.run(args, capture_output=True, text=True, timeout=10)
        if result.returncode == 0:
            print(result.stdout, end='')
        else:
            print(f"Command failed with error:\n{result.stderr}", end='')
    except FileNotFoundError:
        print(f"Command '{command}' not found.")
    except subprocess.TimeoutExpired:
        print("Command timed out.")
    except Exception as e:
        print(f"An error occurred: {e}")

