def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    using safe Python implementations instead of subprocess.
    '''
    # Define a whitelist of allowed commands and their safe implementations
    def cmd_ls(args):
        # Only allow listing current directory; ignore extra arguments
        try:
            entries = os.listdir('.')
            for entry in entries:
                print(entry)
        except Exception as e:
            print(f"Error listing directory: {e}", file=sys.stderr)

    def cmd_echo(args):
        # Print the arguments joined by space
        print(' '.join(args))

    def cmd_cat(args):
        # Read and print files, but only allow files in current directory
        if not args:
            print("cat: missing file operand", file=sys.stderr)
            return
        for filename in args:
            # Prevent directory traversal
            safe_path = os.path.normpath(filename)
            if safe_path.startswith('..') or os.path.isabs(safe_path):
                print(f"cat: {filename}: Permission denied", file=sys.stderr)
                continue
            full_path = os.path.join(os.getcwd(), safe_path)
            if not os.path.exists(full_path):
                print(f"cat: {filename}: No such file", file=sys.stderr)
                continue
            if not os.path.isfile(full_path):
                print(f"cat: {filename}: Is a directory", file=sys.stderr)
                continue
            try:
                with open(full_path, 'r') as f:
                    sys.stdout.write(f.read())
            except Exception as e:
                print(f"cat: {filename}: {e}", file=sys.stderr)

    def cmd_pwd(args):
        # Print current working directory
        print(os.getcwd())

    def cmd_whoami(args):
        # Print current user
        try:
            print(getpass.getuser())
        except Exception as e:
            print(f"whoami: {e}", file=sys.stderr)

    def cmd_date(args):
        # Print current date and time
        print(datetime.datetime.now().strftime("%c"))

    # Map command names to functions
    command_map = {
        'ls': cmd_ls,
        'echo': cmd_echo,
        'cat': cmd_cat,
        'pwd': cmd_pwd,
        'whoami': cmd_whoami,
        'date': cmd_date
    }

    # Read user input
    user_input = input("Enter command: ").strip()

    # Parse the input into a list of arguments
    try:
        args = shlex.split(user_input)
    except ValueError as e:
        print(f"Invalid command syntax: {e}")
        return

    if not args:
        print("No command entered.")
        return

    command = args[0]
    command_args = args[1:]

    # Validate that the command is in the whitelist
    if command not in command_map:
        print(f"Command '{command}' is not allowed.")
        return

    # Execute the command using the safe implementation
    try:
        command_map[command](command_args)
    except Exception as e:
        print(f"An error occurred: {e}")

