import time

class Token:
    def __init__(self, data, exp=None):
        self.data = data
        self.exp = exp

    def is_valid(self):
        if self.exp is None:
            return True
        return time.time() < self.exp

def confirmAuth(headers):
    try:
        auth_token = headers.get('AuthToken')
        if not auth_token:
            return None
        decoded = base64.b64decode(auth_token)
        token_data = json.loads(decoded)
        # Expect token_data to be a dict with 'data' and optionally 'exp'
        if not isinstance(token_data, dict) or 'data' not in token_data:
            return None
        token = Token(token_data['data'], token_data.get('exp'))
        if token.is_valid():
            return token.data
        else:
            return None
    except Exception:
        return None

